(5, 'Succession', 'Succession es una obra maestra de la sátira corporativa. Retrata con cinismo shakesperiano el poder, la codicia y el trauma familiar. Su brillante elenco encarna la podredumbre moral de una élite patética, mientras los diálogos afilados y su banda sonora transforman la miseria humana en puro entretenimiento adictivo.', 5, , 'daniel', 1);
INSERT INTO `resenas` (`id`, `titulo`, `opinion`, `calificacion`, `imagen`, `creador`, `idUsu`) VALUES
(7, 'Twin Peaks', 'Twin Peaks es una obra maestra revolucionaria que desafía cualquier lógica televisiva. David Lynch fusiona el misterio criminal, el melodrama y el terror surrealista en una atmósfera tan hipnótica como perturbadora. Es un viaje inolvidable al corazón del trauma, lo místico y los secretos más oscuros de la naturaleza humana.', 4, , 'daniel', 1);
INSERT INTO `resenas` (`id`, `titulo`, `opinion`, `calificacion`, `imagen`, `creador`, `idUsu`) VALUES
(9, 'Nomadland', 'Nomadland es una obra maestra de la empatía. Frances McDormand brilla en este viaje íntimo y visualmente majestuoso que dignifica la vida al margen del sistema. Chloé Zhao retrata la vejez precarizada, el duelo y la libertad sin caer en el sentimentalismo, transformando la soledad en una conmovedora redención comunitaria.', 5, , 'daniel', 1);

